  // Clear existing filter
  document.querySelectorAll('.cmd-highlight, .cmd-dim').forEach(function(el) {
    el.classList.remove('cmd-highlight', 'cmd-dim');
  });
  if (!keyword || keyword === 'clear' || keyword === 'reset') {
    return 'Filter cleared.';
  }
  // ... skills and cards filtering ...
  return 'Found ' + matchCount + ' match...';
